  21	// Specialization for FUNCTION_WITH_PARAMS
  22	template <>
  23	struct PythonNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS> {
  24		static NativeContext Extract(TSNode node, const string &content) {
  25			NativeContext context;
  26	
  27			// Extract return type if present (for type-annotated functions)
  28			string return_type = ExtractPythonReturnType(node, content);
  29			if (!return_type.empty()) {
  30				context.signature_type = return_type;
  31			}
  32			// Note: For Python, many functions don't have type annotations, so empty signature_type is normal
  33	
  34			// Extract function parameters
  35			context.parameters = ExtractPythonParameters(node, content);
  36	
  37			// Extract decorators if present
  38			auto decorators = ExtractPythonDecorators(node, content);
  39			context.modifiers = decorators;
  40	
  41			return context;
  42		}
  43	
  44	private:
  45		static string ExtractPythonReturnType(TSNode node, const string &content) {
  46			// Look for type annotation after -> in function definition
  47			uint32_t child_count = ts_node_child_count(node);
  48			for (uint32_t i = 0; i < child_count; i++) {
  49				TSNode child = ts_node_child(node, i);
  50				const char *child_type = ts_node_type(child);
  51	
  52				if (strcmp(child_type, "->") == 0 && i + 1 < child_count) {
  53					// Next child should be the return type
  54					TSNode type_node = ts_node_child(node, i + 1);
  55					uint32_t start = ts_node_start_byte(type_node);
  56					uint32_t end = ts_node_end_byte(type_node);
  57					if (start < content.length() && end <= content.length()) {
  58						return content.substr(start, end - start);
  59					}
  60				}
  61			}
  62			return ""; // No return type annotation
  63		}
  64	
  65		static vector<ParameterInfo> ExtractPythonParameters(TSNode node, const string &content) {
  66			vector<ParameterInfo> params;
  67	
  68			// Find parameters node
  69			uint32_t child_count = ts_node_child_count(node);
  70			for (uint32_t i = 0; i < child_count; i++) {
  71				TSNode child = ts_node_child(node, i);
  72				const char *child_type = ts_node_type(child);
  73	
  74				if (strcmp(child_type, "parameters") == 0) {
  75					// Extract each parameter from the parameters list
  76					params = ExtractPythonParametersDirect(child, content);
  77					break;
  78				}
  79			}
  80	
  81			return params;
  82		}
  83	
  84		static vector<ParameterInfo> ExtractPythonParametersDirect(TSNode params_node, const string &content) {
  85			vector<ParameterInfo> parameters;
  86	
  87			uint32_t child_count = ts_node_child_count(params_node);
  88	
  89			for (uint32_t i = 0; i < child_count; i++) {
  90				TSNode child = ts_node_child(params_node, i);
  91				const char *child_type = ts_node_type(child);
  92	
  93				ParameterInfo param;
  94				bool is_valid_param = false;
  95	
  96				if (strcmp(child_type, "identifier") == 0) {
  97					// Simple parameter: def func(param):
  98					uint32_t start = ts_node_start_byte(child);
  99					uint32_t end = ts_node_end_byte(child);
 100					if (start < content.length() && end <= content.length()) {
 101						param.name = content.substr(start, end - start);
 102						is_valid_param = true;
 103					}
 104				} else if (strcmp(child_type, "typed_parameter") == 0) {
 105					// Typed parameter: def func(param: int):
 106					param = ExtractTypedParameter(child, content);
 107					is_valid_param = !param.name.empty();
 108				} else if (strcmp(child_type, "default_parameter") == 0) {
 109					// Parameter with default: def func(param=default):
 110					param = ExtractDefaultParameter(child, content);
 111					is_valid_param = !param.name.empty();
 112				} else if (strcmp(child_type, "typed_default_parameter") == 0) {
 113					// Typed parameter with default: def func(param: int = default):
 114					param = ExtractTypedDefaultParameter(child, content);
 115					is_valid_param = !param.name.empty();
 116				}
 117	
 118				if (is_valid_param) {
 119					parameters.push_back(param);
 120				}
 121			}
 122	
 123			return parameters;
 124		}
