 152		static ParameterInfo ExtractDefaultParameter(TSNode node, const string &content) {
 153			ParameterInfo param;
 154			param.is_optional = true;
 155			uint32_t child_count = ts_node_child_count(node);
 156	
 157			for (uint32_t i = 0; i < child_count; i++) {
