 198					if (start < content.length() && end <= content.length()) {
 199						param.type = content.substr(start, end - start);
 200					}
 201				} else if (strcmp(child_type, "=") != 0 && strcmp(child_type, "identifier") != 0 &&
 202				           strcmp(child_type, "type") != 0 && strcmp(child_type, ":") != 0) {
 203					// This is likely the default value
 204					uint32_t start = ts_node_start_byte(child);
 205					uint32_t end = ts_node_end_byte(child);
 206					if (start < content.length() && end <= content.length()) {
 207						param.default_value = content.substr(start, end - start);
 208					}
 209				}
 210			}
 211	
 212			return param;
 213		}
