 215		static vector<string> ExtractPythonDecorators(TSNode node, const string &content) {
 216			vector<string> decorators;
 217	
 218			// Check if this function has decorators (they appear as siblings before the function)
 219			TSNode parent = ts_node_parent(node);
 220			if (!ts_node_is_null(parent)) {
 221				uint32_t child_count = ts_node_child_count(parent);
 222				for (uint32_t i = 0; i < child_count; i++) {
 223					TSNode child = ts_node_child(parent, i);
 224					const char *child_type = ts_node_type(child);
 225	
 226					if (strcmp(child_type, "decorator") == 0) {
 227						// Extract decorator name
 228						uint32_t start = ts_node_start_byte(child);
 229						uint32_t end = ts_node_end_byte(child);
 230						if (start < content.length() && end <= content.length()) {
 231							string decorator_text = content.substr(start, end - start);
 232							decorators.push_back(decorator_text);
 233						}
 234					}
 235				}
 236			}
 237	
 238			return decorators;
 239		}
 240	};
