 253	// Specialization for CLASS_WITH_METHODS
 254	template <>
 255	struct PythonNativeExtractor<NativeExtractionStrategy::CLASS_WITH_METHODS> {
 256		static NativeContext Extract(TSNode node, const string &content) {
 257			NativeContext context;
 258	
 259			try {
 260				string node_type = ts_node_type(node);
 261	
 262				if (node_type == "class_definition") {
 263					context.signature_type = ExtractClassType(node, content);
 264					context.parameters = ExtractBaseClassesAsParameters(node, content);
 265					context.modifiers = ExtractPythonClassModifiers(node, content, !context.parameters.empty());
 266				} else if (node_type == "decorated_definition") {
 267					context.signature_type = ExtractDecoratedClassType(node, content);
 268					context.parameters = ExtractDecoratedBaseClassesAsParameters(node, content);
 269					context.modifiers = ExtractDecoratedClassModifiers(node, content, !context.parameters.empty());
 270				} else {
 271					// Default class extraction
 272					context.signature_type = "class";
 273					vector<string> base_classes = ExtractPythonBaseClasses(node, content);
 274					for (const string &base : base_classes) {
 275						context.parameters.push_back({base, "extends"});
 276					}
 277				}
 278			} catch (...) {
 279				context.signature_type = "class";
 280				context.modifiers.clear();
 281				context.parameters.clear();
 282			}
 283	
 284			return context;
 285		}
 286	
 287	private:
 288		static string ExtractClassType(TSNode node, const string &content) {
 289			// Check for special class types based on base classes and content
 290			vector<string> base_classes = ExtractPythonBaseClasses(node, content);
 291	
 292			// Check for common patterns
 293			for (const string &base : base_classes) {
 294				if (base == "ABC" || base == "AbstractBase") {
 295					return "abstract_class";
 296				} else if (base == "Enum") {
 297					return "enum_class";
 298				} else if (base == "IntEnum") {
 299					return "int_enum_class";
 300				} else if (base == "Exception" || base.find("Exception") != string::npos) {
 301					return "exception_class";
 302				} else if (base == "type") {
 303					return "metaclass";
 304				}
 305			}
 306	
 307			// Check for class body to detect special patterns
 308			if (HasAbstractMethods(node, content)) {
 309				return "abstract_class";
 310			}
 311	
 312			if (HasDataclassDecorator(node, content)) {
 313				return "dataclass";
 314			}
 315	
 316			return "class";
 317		}
 318	
 319		static string ExtractDecoratedClassType(TSNode node, const string &content) {
 320			// For decorated classes, extract the class type from the inner definition
 321			uint32_t child_count = ts_node_child_count(node);
 322			for (uint32_t i = 0; i < child_count; i++) {
 323				TSNode child = ts_node_child(node, i);
 324				const char *child_type = ts_node_type(child);
 325	
 326				if (strcmp(child_type, "class_definition") == 0) {
 327					string base_type = ExtractClassType(child, content);
 328	
 329					// Check decorators for type modification
 330					vector<string> decorators = ExtractClassDecorators(node, content);
 331					for (const string &decorator : decorators) {
 332						if (decorator.find("@dataclass") != string::npos) {
 333							return "dataclass";
 334						} else if (decorator.find("@attr.s") != string::npos || decorator.find("@attrs") != string::npos) {
 335							return "attrs_class";
 336						} else if (decorator.find("@final") != string::npos) {
 337							return "final_class";
 338						}
 339					}
 340	
 341					return "decorated_" + base_type;
 342				}
 343			}
 344	
 345			return "decorated_class";
 346		}
 347	
 348		// Extract base classes as ParameterInfo objects (parent classes go in parameters)
 349		// Python doesn't distinguish extends/implements, so all parents are "extends"
 350		static vector<ParameterInfo> ExtractBaseClassesAsParameters(TSNode node, const string &content) {
 351			vector<ParameterInfo> params;
 352			vector<string> base_classes = ExtractPythonBaseClasses(node, content);
 353			for (const string &base : base_classes) {
 354				params.push_back({base, "extends"}); // name = class name, type = inheritance kind
 355			}
 356			return params;
 357		}
 358	
 359		// Extract base classes from decorated class definition
 360		static vector<ParameterInfo> ExtractDecoratedBaseClassesAsParameters(TSNode node, const string &content) {
 361			uint32_t child_count = ts_node_child_count(node);
 362			for (uint32_t i = 0; i < child_count; i++) {
 363				TSNode child = ts_node_child(node, i);
 364				if (strcmp(ts_node_type(child), "class_definition") == 0) {
 365					return ExtractBaseClassesAsParameters(child, content);
 366				}
 367			}
 368			return {};
 369		}
 370	
 371		// Extract class modifiers (abstract, has_classmethods, etc.)
 372		// Note: inheritance info is now in ParameterInfo.type, not in modifiers
 373		static vector<string> ExtractPythonClassModifiers(TSNode node, const string &content, bool has_parents = false) {
 374			vector<string> modifiers;
 375	
 376			// Check for special method patterns
 377			if (HasAbstractMethods(node, content)) {
 378				modifiers.push_back("abstract");
 379			}
 380	
 381			if (HasClassMethods(node, content)) {
 382				modifiers.push_back("has_classmethods");
 383			}
 384	
 385			if (HasStaticMethods(node, content)) {
 386				modifiers.push_back("has_staticmethods");
 387			}
 388	
 389			if (HasProperties(node, content)) {
 390				modifiers.push_back("has_properties");
 391			}
 392	
 393			if (HasDunderMethods(node, content)) {
 394				modifiers.push_back("has_dunder_methods");
 395			}
 396	
 397			return modifiers;
 398		}
