 400		static vector<string> ExtractDecoratedClassModifiers(TSNode node, const string &content, bool has_parents = false) {
 401			vector<string> modifiers;
 402	
 403			// Extract decorators
 404			vector<string> decorators = ExtractClassDecorators(node, content);
 405			for (const string &decorator : decorators) {
 406				modifiers.push_back(decorator);
 407			}
 408	
 409			// Get base class modifiers from the inner class definition
 410			uint32_t child_count = ts_node_child_count(node);
 411			for (uint32_t i = 0; i < child_count; i++) {
 412				TSNode child = ts_node_child(node, i);
 413				const char *child_type = ts_node_type(child);
 414	
 415				if (strcmp(child_type, "class_definition") == 0) {
 416					vector<string> class_modifiers = ExtractPythonClassModifiers(child, content, has_parents);
 417					modifiers.insert(modifiers.end(), class_modifiers.begin(), class_modifiers.end());
 418					break;
 419				}
 420			}
 421	
 422			return modifiers;
 423		}
