 425		static vector<string> ExtractPythonBaseClasses(TSNode node, const string &content) {
 426			vector<string> base_classes;
 427	
 428			// Find argument_list node which contains base classes
 429			uint32_t child_count = ts_node_child_count(node);
 430			for (uint32_t i = 0; i < child_count; i++) {
 431				TSNode child = ts_node_child(node, i);
 432				const char *child_type = ts_node_type(child);
 433	
 434				if (strcmp(child_type, "argument_list") == 0) {
 435					// Extract base class names
 436					uint32_t arg_count = ts_node_child_count(child);
 437					for (uint32_t j = 0; j < arg_count; j++) {
 438						TSNode arg = ts_node_child(child, j);
 439						string arg_type = ts_node_type(arg);
 440	
 441						if (arg_type == "identifier" || arg_type == "attribute") {
 442							uint32_t start = ts_node_start_byte(arg);
 443							uint32_t end = ts_node_end_byte(arg);
 444							if (start < content.length() && end <= content.length()) {
 445								string base_class = content.substr(start, end - start);
 446								base_classes.push_back(base_class);
 447							}
 448						}
 449					}
 450					break;
 451				}
 452			}
 453	
 454			return base_classes;
 455		}
