 457		static vector<string> ExtractClassDecorators(TSNode node, const string &content) {
 458			vector<string> decorators;
 459	
 460			uint32_t child_count = ts_node_child_count(node);
 461			for (uint32_t i = 0; i < child_count; i++) {
 462				TSNode child = ts_node_child(node, i);
 463				const char *child_type = ts_node_type(child);
 464	
 465				if (strcmp(child_type, "decorator") == 0) {
 466					uint32_t start = ts_node_start_byte(child);
 467					uint32_t end = ts_node_end_byte(child);
 468					if (start < content.length() && end <= content.length()) {
 469						string decorator_text = content.substr(start, end - start);
 470						decorators.push_back(decorator_text);
 471					}
 472				}
 473			}
 474	
 475			return decorators;
 476		}
