 478		static bool HasAbstractMethods(TSNode node, const string &content) {
 479			uint32_t child_count = ts_node_child_count(node);
 480			for (uint32_t i = 0; i < child_count; i++) {
 481				TSNode child = ts_node_child(node, i);
 482				const char *child_type = ts_node_type(child);
 483	
 484				if (strcmp(child_type, "block") == 0) {
 485					// Check for @abstractmethod decorator in the block
 486					uint32_t block_count = ts_node_child_count(child);
 487					for (uint32_t j = 0; j < block_count; j++) {
 488						TSNode block_child = ts_node_child(child, j);
 489						const char *block_child_type = ts_node_type(block_child);
 490	
 491						if (strcmp(block_child_type, "decorated_definition") == 0) {
 492							uint32_t start = ts_node_start_byte(block_child);
 493							uint32_t end = ts_node_end_byte(block_child);
 494							if (start < content.length() && end <= content.length()) {
 495								string method_text = content.substr(start, end - start);
 496								if (method_text.find("@abstractmethod") != string::npos) {
 497									return true;
 498								}
 499							}
 500						}
 501					}
 502				}
 503			}
 504	
 505			return false;
 506		}
