 508		static bool HasClassMethods(TSNode node, const string &content) {
 509			uint32_t child_count = ts_node_child_count(node);
 510			for (uint32_t i = 0; i < child_count; i++) {
 511				TSNode child = ts_node_child(node, i);
 512				const char *child_type = ts_node_type(child);
 513	
 514				if (strcmp(child_type, "block") == 0) {
 515					uint32_t start = ts_node_start_byte(child);
 516					uint32_t end = ts_node_end_byte(child);
 517					if (start < content.length() && end <= content.length()) {
 518						string class_text = content.substr(start, end - start);
 519						if (class_text.find("@classmethod") != string::npos) {
 520							return true;
 521						}
 522					}
 523				}
 524			}
 525	
 526			return false;
 527		}
