 617			NativeContext context;
 618	
 619			try {
 620				string node_type = ts_node_type(node);
 621	
 622				if (node_type == "typed_parameter") {
 623					context.signature_type = ExtractTypedParameterType(node, content);
 624					context.modifiers = ExtractTypedParameterModifiers(node, content);
 625				} else if (node_type == "type") {
 626					context.signature_type = ExtractTypeText(node, content);
 627					context.modifiers = ExtractTypeModifiers(node, content);
 628				} else if (node_type == "identifier") {
 629					context.signature_type = ExtractIdentifierType(node, content);
 630					context.modifiers = ExtractIdentifierModifiers(node, content);
 631				} else if (node_type == "dotted_name") {
 632					context.signature_type = ExtractDottedNameType(node, content);
 633					context.modifiers = ExtractDottedNameModifiers(node, content);
 634				} else if (node_type == "assignment") {
 635					context.signature_type = ExtractAssignmentType(node, content);
 636					context.modifiers = ExtractAssignmentModifiers(node, content);
 637				} else if (node_type == "annotated_assignment") {
 638					context.signature_type = ExtractAnnotatedAssignmentType(node, content);
 639					context.modifiers = ExtractAnnotatedAssignmentModifiers(node, content);
 640				} else if (node_type == "attribute") {
 641					context.signature_type = ExtractAttributeType(node, content);
 642					context.modifiers = ExtractAttributeModifiers(node, content);
 643				} else if (node_type == "subscript") {
 644					context.signature_type = ExtractSubscriptType(node, content);
 645					context.modifiers = ExtractSubscriptModifiers(node, content);
 646				} else if (node_type == "list_comprehension" || node_type == "set_comprehension" ||
 647				           node_type == "dictionary_comprehension" || node_type == "generator_expression") {
 648					context.signature_type = ExtractComprehensionType(node, content);
 649					context.modifiers = ExtractComprehensionModifiers(node, content);
 650				} else {
 651					// For other types, try to extract type annotation if present
 652					uint32_t child_count = ts_node_child_count(node);
 653					for (uint32_t i = 0; i < child_count; i++) {
 654						TSNode child = ts_node_child(node, i);
 655						const char *child_type = ts_node_type(child);
 656	
 657						if (strcmp(child_type, "type") == 0) {
 658							uint32_t start = ts_node_start_byte(child);
 659							uint32_t end = ts_node_end_byte(child);
 660							if (start < content.length() && end <= content.length()) {
 661								context.signature_type = content.substr(start, end - start);
 662							}
 663							break;
 664						}
 665					}
 666				}
 667			} catch (...) {
 668				context.signature_type = "";
 669				context.modifiers.clear();
 670			}
 671	
 672			return context;
 673		}
