 762					return ExtractAnnotatedAssignmentType(parent, content);
 763				} else if (parent_type == "attribute") {
 764					return "attribute_access";
 765				} else if (parent_type == "call") {
 766					return "function_call";
 767				} else if (parent_type == "import_statement" || parent_type == "import_from_statement") {
 768					return "import";
 769				} else if (parent_type == "class_definition") {
 770					return "class_name";
 771				} else if (parent_type == "function_definition") {
 772					return "function_name";
 773				}
