 993		static string InferTypeFromValue(TSNode value_node, const string &content) {
 994			string value_type = ts_node_type(value_node);
 995	
 996			if (value_type == "integer") {
 997				return "int";
 998			} else if (value_type == "float") {
 999				return "float";
1000			} else if (value_type == "string") {
1001				return "str";
1002			} else if (value_type == "true" || value_type == "false") {
1003				return "bool";
1004			} else if (value_type == "none") {
1005				return "None";
1006			} else if (value_type == "list") {
1007				return "list";
1008			} else if (value_type == "dictionary") {
1009				return "dict";
1010			} else if (value_type == "set") {
1011				return "set";
1012			} else if (value_type == "tuple") {
1013				return "tuple";
1014			} else if (value_type == "call") {
1015				// Try to extract function name for call inference
1016				uint32_t child_count = ts_node_child_count(value_node);
1017				if (child_count > 0) {
1018					TSNode func_node = ts_node_child(value_node, 0);
1019					uint32_t start = ts_node_start_byte(func_node);
1020					uint32_t end = ts_node_end_byte(func_node);
1021					if (start < content.length() && end <= content.length()) {
1022						return content.substr(start, end - start);
1023					}
1024				}
1025				return "function_call";
1026			} else if (value_type == "attribute") {
1027				// For attribute access like obj.method
1028				uint32_t start = ts_node_start_byte(value_node);
1029				uint32_t end = ts_node_end_byte(value_node);
1030				if (start < content.length() && end <= content.length()) {
1031					return content.substr(start, end - start);
1032				}
1033				return "attribute";
1034			}
1035	
1036			return "inferred";
1037		}
