1048	// Specialization for FUNCTION_WITH_DECORATORS (Python functions with @decorators)
1049	template <>
1050	struct PythonNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_DECORATORS> {
1051		static NativeContext Extract(TSNode node, const string &content) {
1052			NativeContext context;
1053	
1054			try {
1055				string node_type = ts_node_type(node);
1056	
1057				if (node_type == "function_definition" || node_type == "async_function_definition") {
1058					// Start with basic function extraction
1059					context = PythonNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS>::Extract(node, content);
1060	
1061					// Add decorators and advanced modifiers
1062					vector<string> decorators = ExtractPythonFunctionDecorators(node, content);
1063					vector<string> advanced_modifiers = ExtractPythonAdvancedModifiers(node, content);
1064	
1065					// Combine existing modifiers with decorators and advanced modifiers
1066					context.modifiers.insert(context.modifiers.end(), decorators.begin(), decorators.end());
1067					context.modifiers.insert(context.modifiers.end(), advanced_modifiers.begin(), advanced_modifiers.end());
1068	
1069					// Enhance signature type with decorator info
1070					if (!decorators.empty()) {
1071						context.signature_type = "decorated_" + context.signature_type;
1072					}
1073	
1074					// Handle async functions
1075					if (node_type == "async_function_definition") {
1076						context.signature_type = "async_" + context.signature_type;
1077						context.modifiers.insert(context.modifiers.begin(), "async");
1078					}
1079				} else if (node_type == "decorated_definition") {
1080					context = ExtractDecoratedFunction(node, content);
1081				} else {
1082					// Fallback to basic function extraction
1083					context = PythonNativeExtractor<NativeExtractionStrategy::FUNCTION_WITH_PARAMS>::Extract(node, content);
1084				}
1085			} catch (...) {
1086				context.signature_type = "";
1087				context.parameters.clear();
1088				context.modifiers.clear();
1089			}
1090	
1091			return context;
1092		}
1093	
1094	private:
1095		static vector<string> ExtractPythonFunctionDecorators(TSNode node, const string &content) {
1096			vector<string> decorators;
1097	
