1289	// Specialization for IMPORT_STATEMENT (Python import statements)
1290	template <>
1291	struct PythonNativeExtractor<NativeExtractionStrategy::IMPORT_STATEMENT> {
1292		static NativeContext Extract(TSNode node, const string &content) {
1293			NativeContext context;
1294	
1295			try {
1296				string node_type = ts_node_type(node);
1297	
1298				if (node_type == "import_statement") {
1299					context.signature_type = ExtractImportType(node, content);
1300					context.modifiers = ExtractImportModifiers(node, content);
1301				} else if (node_type == "import_from_statement") {
1302					context.signature_type = ExtractImportFromType(node, content);
1303					context.modifiers = ExtractImportFromModifiers(node, content);
1304				} else if (node_type == "dotted_name") {
1305					context.signature_type = ExtractDottedImportType(node, content);
1306					context.modifiers = ExtractDottedImportModifiers(node, content);
1307				} else if (node_type == "aliased_import") {
1308					context.signature_type = ExtractAliasedImportType(node, content);
1309					context.modifiers = ExtractAliasedImportModifiers(node, content);
1310				} else if (node_type == "wildcard_import") {
1311					context.signature_type = "wildcard_import";
1312					context.modifiers.push_back("wildcard");
1313				} else {
1314					context.signature_type = "import";
1315					context.modifiers.push_back("import_statement");
1316				}
1317			} catch (...) {
1318				context.signature_type = "";
1319				context.modifiers.clear();
1320			}
1321	
1322			return context;
1323		}
