1326		static string ExtractImportType(TSNode node, const string &content) {
1327			// For regular imports: import module
1328			uint32_t child_count = ts_node_child_count(node);
1329			for (uint32_t i = 0; i < child_count; i++) {
1330				TSNode child = ts_node_child(node, i);
1331				string child_type = ts_node_type(child);
1332	
1333				if (child_type == "dotted_name" || child_type == "identifier") {
1334					string module_name = ExtractNodeText(child, content);
1335					if (!module_name.empty()) {
1336						return "import_" + module_name;
1337					}
1338				} else if (child_type == "aliased_import") {
1339					return "aliased_import";
1340				}
1341			}
