1369		static string ExtractImportFromType(TSNode node, const string &content) {
1370			// For from imports: from module import item
1371			string module_name = "";
1372			string import_items = "";
1373	
1374			uint32_t child_count = ts_node_child_count(node);
1375			for (uint32_t i = 0; i < child_count; i++) {
1376				TSNode child = ts_node_child(node, i);
1377				string child_type = ts_node_type(child);
