1379				if (child_type == "dotted_name" || child_type == "identifier") {
1380					if (module_name.empty()) {
1381						module_name = ExtractNodeText(child, content);
1382					}
1383				} else if (child_type == "import_list") {
1384					// Extract what's being imported
1385					uint32_t import_count = ts_node_child_count(child);
1386					for (uint32_t j = 0; j < import_count; j++) {
1387						TSNode import_item = ts_node_child(child, j);
