1410			vector<string> modifiers;
1411			modifiers.push_back("from_import");
1412	
1413			uint32_t child_count = ts_node_child_count(node);
1414			for (uint32_t i = 0; i < child_count; i++) {
1415				TSNode child = ts_node_child(node, i);
1416				string child_type = ts_node_type(child);
1417	
1418				if (child_type == "dotted_name") {
1419					modifiers.push_back("from_dotted_module");
1420					string module_name = ExtractNodeText(child, content);
1421					if (module_name.find(".") != string::npos) {
1422						modifiers.push_back("nested_module");
1423					}
1424				} else if (child_type == "relative_import") {
1425					modifiers.push_back("relative_import");
1426				} else if (child_type == "import_list") {
1427					modifiers.push_back("specific_imports");
1428	
1429					// Count imported items
1430					uint32_t import_count = ts_node_child_count(child);
1431					int item_count = 0;
1432					bool has_aliases = false;
1433	
1434					for (uint32_t j = 0; j < import_count; j++) {
1435						TSNode import_item = ts_node_child(child, j);
1436						string import_type = ts_node_type(import_item);
1437	
1438						if (import_type == "identifier") {
1439							item_count++;
1440						} else if (import_type == "aliased_import") {
1441							item_count++;
1442							has_aliases = true;
1443						}
1444					}
1445	
1446					if (item_count > 1) {
1447						modifiers.push_back("multiple_imports");
1448					}
1449					if (has_aliases) {
1450						modifiers.push_back("with_aliases");
1451					}
1452				} else if (child_type == "wildcard_import") {
1453					modifiers.push_back("wildcard_import");
1454				}
1455			}
1456	
1457			return modifiers;
1458		}
