     8	// Scalar function that converts semantic_type integer to human-readable string
     9	static void SemanticTypeToStringFunction(DataChunk &args, ExpressionState &state, Vector &result) {
    10		D_ASSERT(args.ColumnCount() == 1);
    11	
    12		auto &semantic_type_vector = args.data[0];
    13		auto count = args.size();
    14	
    15		UnaryExecutor::Execute<uint8_t, string_t>(semantic_type_vector, result, count, [&](uint8_t semantic_type) {
    16			// For backward compatibility, mask out refinement bits but only for refined types
    17			// Check if this could be a valid refined type (base type exists + has refinements)
    18			uint8_t refinement_bits = semantic_type & 0x03;
    19			uint8_t base_semantic_type = semantic_type & 0xFC;
    20	
    21			if (refinement_bits != 0) {
    22				// Has refinement bits - check if base type is valid
    23				string base_type_name = SemanticTypes::GetSemanticTypeName(base_semantic_type);
    24				if (base_type_name != "UNKNOWN_SEMANTIC_TYPE") {
    25					// Valid base type with refinements - return base type name for compatibility
    26					return StringVector::AddString(result, base_type_name);
    27				}
    28			}
    29	
    30			// No refinements or invalid base type - return as-is (might be UNKNOWN)
    31			string type_name = SemanticTypes::GetSemanticTypeName(semantic_type);
    32			return StringVector::AddString(result, type_name);
    33		});
    34	}
