   288	// Check if a string contains any of the patterns in a list
   289	// string_contains_any(str, ['pattern1', 'pattern2', ...]) -> BOOLEAN
   290	// Case-sensitive by default
   291	static void StringContainsAnyFunction(DataChunk &args, ExpressionState &state, Vector &result) {
   292		D_ASSERT(args.ColumnCount() == 2);
   293	
   294		auto &str_vector = args.data[0];
   295		auto &patterns_vector = args.data[1];
   296		auto count = args.size();
   297	
   298		// Get unified format for both vectors
   299		UnifiedVectorFormat str_data;
   300		str_vector.ToUnifiedFormat(count, str_data);
   301		auto str_entries = UnifiedVectorFormat::GetData<string_t>(str_data);
   302	
   303		UnifiedVectorFormat patterns_data;
   304		patterns_vector.ToUnifiedFormat(count, patterns_data);
   305		auto patterns_entries = UnifiedVectorFormat::GetData<list_entry_t>(patterns_data);
   306	
   307		// Get the child vector containing the actual pattern strings
   308		auto &patterns_child = ListVector::GetEntry(patterns_vector);
   309		UnifiedVectorFormat patterns_child_data;
   310		patterns_child.ToUnifiedFormat(ListVector::GetListSize(patterns_vector), patterns_child_data);
   311		auto patterns_child_entries = UnifiedVectorFormat::GetData<string_t>(patterns_child_data);
   312	
   313		auto result_data = FlatVector::GetData<bool>(result);
   314		auto &result_validity = FlatVector::Validity(result);
   315	
   316		for (idx_t i = 0; i < count; i++) {
   317			auto str_idx = str_data.sel->get_index(i);
   318			auto patterns_idx = patterns_data.sel->get_index(i);
   319	
   320			// Handle NULL inputs
   321			if (!str_data.validity.RowIsValid(str_idx) || !patterns_data.validity.RowIsValid(patterns_idx)) {
   322				result_validity.SetInvalid(i);
   323				continue;
   324			}
   325	
   326			auto str = str_entries[str_idx].GetString();
   327			auto &list_entry = patterns_entries[patterns_idx];
   328	
   329			bool found = false;
   330			for (idx_t j = 0; j < list_entry.length; j++) {
   331				auto pattern_idx = patterns_child_data.sel->get_index(list_entry.offset + j);
   332				if (!patterns_child_data.validity.RowIsValid(pattern_idx)) {
   333					continue; // Skip NULL patterns
   334				}
   335				auto pattern = patterns_child_entries[pattern_idx].GetString();
   336				if (str.find(pattern) != string::npos) {
   337					found = true;
   338					break;
   339				}
   340			}
   341			result_data[i] = found;
   342		}
   343	}
   344	
   345	// Case-insensitive version
   346	// string_contains_any_i(str, ['pattern1', 'pattern2', ...]) -> BOOLEAN
   347	static void StringContainsAnyIFunction(DataChunk &args, ExpressionState &state, Vector &result) {
   348		D_ASSERT(args.ColumnCount() == 2);
   349	
   350		auto &str_vector = args.data[0];
   351		auto &patterns_vector = args.data[1];
   352		auto count = args.size();
   353	
   354		// Get unified format for both vectors
   355		UnifiedVectorFormat str_data;
   356		str_vector.ToUnifiedFormat(count, str_data);
   357		auto str_entries = UnifiedVectorFormat::GetData<string_t>(str_data);
   358	
   359		UnifiedVectorFormat patterns_data;
   360		patterns_vector.ToUnifiedFormat(count, patterns_data);
   361		auto patterns_entries = UnifiedVectorFormat::GetData<list_entry_t>(patterns_data);
   362	
   363		// Get the child vector containing the actual pattern strings
   364		auto &patterns_child = ListVector::GetEntry(patterns_vector);
   365		UnifiedVectorFormat patterns_child_data;
   366		patterns_child.ToUnifiedFormat(ListVector::GetListSize(patterns_vector), patterns_child_data);
   367		auto patterns_child_entries = UnifiedVectorFormat::GetData<string_t>(patterns_child_data);
   368	
   369		auto result_data = FlatVector::GetData<bool>(result);
   370		auto &result_validity = FlatVector::Validity(result);
   371	
   372		// Helper to convert string to lowercase
   373		auto to_lower = [](const string &s) {
   374			string result;
   375			result.reserve(s.size());
   376			for (char c : s) {
   377				result += static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
   378			}
   379			return result;
   380		};
   381	
   382		for (idx_t i = 0; i < count; i++) {
   383			auto str_idx = str_data.sel->get_index(i);
   384			auto patterns_idx = patterns_data.sel->get_index(i);
   385	
   386			// Handle NULL inputs
   387			if (!str_data.validity.RowIsValid(str_idx) || !patterns_data.validity.RowIsValid(patterns_idx)) {
   388				result_validity.SetInvalid(i);
   389				continue;
   390			}
   391	
   392			auto str = to_lower(str_entries[str_idx].GetString());
   393			auto &list_entry = patterns_entries[patterns_idx];
   394	
   395			bool found = false;
   396			for (idx_t j = 0; j < list_entry.length; j++) {
   397				auto pattern_idx = patterns_child_data.sel->get_index(list_entry.offset + j);
   398				if (!patterns_child_data.validity.RowIsValid(pattern_idx)) {
   399					continue; // Skip NULL patterns
   400				}
   401				auto pattern = to_lower(patterns_child_entries[pattern_idx].GetString());
   402				if (str.find(pattern) != string::npos) {
   403					found = true;
   404					break;
   405				}
   406			}
   407			result_data[i] = found;
   408		}
   409	}
