   411	// Function that returns list of searchable semantic types
   412	static void GetSearchableTypesFunction(DataChunk &args, ExpressionState &state, Vector &result) {
   413		D_ASSERT(args.ColumnCount() == 0);
   414	
   415		auto searchable_types = SemanticTypes::GetSearchableTypes();
   416		auto count = args.size();
   417	
   418		// Create a list value for each row
   419		auto &list_vector = result;
   420		auto list_entries = FlatVector::GetData<list_entry_t>(list_vector);
   421	
   422		// Create child vector to hold the semantic type values
   423		auto list_size = searchable_types.size();
   424		ListVector::Reserve(list_vector, list_size * count);
   425		auto &child_vector = ListVector::GetEntry(list_vector);
   426		auto child_data = FlatVector::GetData<uint8_t>(child_vector);
   427	
   428		idx_t offset = 0;
   429		for (idx_t i = 0; i < count; i++) {
   430			list_entries[i].offset = offset;
   431			list_entries[i].length = list_size;
   432	
   433			// Copy semantic types to child vector
   434			for (idx_t j = 0; j < list_size; j++) {
   435				child_data[offset + j] = searchable_types[j];
   436			}
   437			offset += list_size;
   438		}
   439	
   440		ListVector::SetListSize(list_vector, offset);
   441	}
