 64	// Function that checks if semantic type matches a specific pattern
 65	static void IsSemanticTypeFunction(DataChunk &args, ExpressionState &state, Vector &result) {
 66		D_ASSERT(args.ColumnCount() == 2);
 67	
 68		auto &semantic_type_vector = args.data[0];
 69		auto &pattern_vector = args.data[1];
 70		auto count = args.size();
 71	
 72		BinaryExecutor::Execute<uint8_t, string_t, bool>(
 73		    semantic_type_vector, pattern_vector, result, count, [&](uint8_t semantic_type, string_t pattern_str) {
 74			    string pattern = pattern_str.GetString();
 75			    uint8_t type = semantic_type;
 76			    uint8_t base_type = semantic_type & 0xFC; // Mask refinement bits for base comparisons
 77	
 78			    // Support common patterns
 79			    if (pattern == "FUNCTION") {
 80				    return base_type == SemanticTypes::DEFINITION_FUNCTION;
 81			    } else if (pattern == "CLASS") {
 82				    return base_type == SemanticTypes::DEFINITION_CLASS;
 83			    } else if (pattern == "VARIABLE") {
 84				    return base_type == SemanticTypes::DEFINITION_VARIABLE;
 85			    } else if (pattern == "IDENTIFIER") {
 86				    return base_type == SemanticTypes::NAME_IDENTIFIER;
 87			    } else if (pattern == "CALL") {
 88				    return base_type == SemanticTypes::COMPUTATION_CALL;
 89			    } else if (pattern == "LITERAL") {
 90				    return (base_type & 0xF0) == SemanticTypes::LITERAL;
 91			    } else if (pattern == "DEFINITION") {
 92				    return (base_type & 0xF0) == SemanticTypes::DEFINITION;
 93			    } else if (pattern == "COMPUTATION") {
 94				    return (base_type & 0xC0) == SemanticTypes::COMPUTATION;
 95			    }
 96	
 97			    // Default: exact string match with base semantic type name
 98			    return SemanticTypes::GetSemanticTypeName(base_type) == pattern;
 99		    });
100	}
